head.script:
scwin.chk_flag = "";

scwin.MSG_FS_WRN_007 = "존재하지않는 매출항목코드입니다.";
scwin.MSG_FS_WRN_008 = "저장된 코드가 아닙니다. 저장을 먼저 하십시오.";
scwin.MSG_FS_WRN_010 = "저장할 데이타가 존재하지 않습니다.";
scwin.MSG_FS_WRN_011 = "거래처코드를 먼저 입력하십시오.";
scwin.MSG_FS_WRN_012 = "매출항목을 먼저 입력하십시오.";
scwin.MSG_FS_WRN_013 = "청구서 유형코드가 존재하지 않습니다.";

scwin.onpageload = function() {
    rd_fmlaClsCd.setValue("01");
    rd_clntCd.setValue("공통");
    $c.gus.cfDisableObjects([btn_addRow, btn_deleteRow, btn_cancelRow, btn_addRow2, btn_deleteRow2, btn_cancelRow2]);
    $c.gus.cfDisableBtn([btn_save]);
};

scwin.onUdcCompleted = function() {
    ed_bilgLoofcCd.setFocus();
};

scwin.f_FormulaListSetDataHeader = function() {
    dma_formulalist_con.set("bilgLoofcCd", ed_bilgLoofcCd.getValue());
    dma_formulalist_con.set("fmlaClsCd", rd_fmlaClsCd.getValue());
};

scwin.f_FormulaSellItemListSetDataHeader = function() {
    let row = ds_formulalist.getRowPosition();
    dma_formulasellitemlist_con.set("bilgLoofcCd", ed_bilgLoofcCd.getValue());
    dma_formulasellitemlist_con.set("fmlaPatternCd", ds_formulalist.getCellData(row, "fmlaPatternCd"));
    dma_formulasellitemlist_con.set("fmlaClsCd", ds_formulalist.getCellData(row, "fmlaClsCd"));
    if (rd_clntCd.getValue() == "거래처") {
        let custRow = ds_formulacustomerlist.getRowPosition();
        dma_formulasellitemlist_con.set("clntNo", ds_formulacustomerlist.getCellData(custRow, "clntNo"));
    } else {
        dma_formulasellitemlist_con.set("clntNo", "0");
    }
};

scwin.f_Retrieve = async function() {
    let chk = await $c.gus.cfValidate([ed_bilgLoofcCd]);
    if (!chk) {
        return;
    }

    if (rd_fmlaClsCd.getValue() == "01") {
        grp_group5.setStyle("display", "none");
        gr_formulasellitemlist.setStyle("height", "440px");
    } else if (rd_fmlaClsCd.getValue() == "03") {
        grp_group5.setStyle("display", "block");
        gr_formulasellitemlist.setStyle("height", "205px");
    }

    if (rd_clntCd.getValue() == "거래처") {
        gr_formulalist.setStyle("height", "205px");
        grp_group4.setStyle("display", "block");
    } else {
        gr_formulalist.setStyle("height", "440px");
        grp_group4.setStyle("display", "none");
    }

    scwin.f_FormulaListSetDataHeader();
    await $c.sbm.execute(sbm_formulalist_retrieve);
};

scwin.f_CustomerAddRow = async function() {
    let row = ds_formulalist.getRowPosition();
    if (ds_formulalist.getRowCount() < 1 || ds_formulalist.getCellData(row, "fmlaPatternCd") == "") {
        await $c.gus.cfAlertMsg(scwin.MSG_FS_WRN_013);
        return;
    }
    let newRow = ds_formulacustomerlist.insertRow();
    ds_formulacustomerlist.setCellData(newRow, "bilgLoofcCd", ed_bilgLoofcCd.getValue());
    ds_formulacustomerlist.setCellData(newRow, "fmlaPatternCd", ds_formulalist.getCellData(row, "fmlaPatternCd"));
    ds_formulacustomerlist.setCellData(newRow, "fmlaClsCd", ds_formulalist.getCellData(row, "fmlaClsCd"));
    if (rd_clntCd.getValue() == "공통") {
        ds_formulacustomerlist.setCellData(newRow, "clntNo", "0");
        ds_formulacustomerlist.setCellData(newRow, "billbilgUnitclsCd", "01");
    }
};

scwin.f_SellItemAddRow = async function() {
    if (rd_clntCd.getValue() == "공통" && ds_formulacustomerlist.getRowCount() < 1) {
        await scwin.f_CustomerAddRow();
    }

    if (rd_clntCd.getValue() == "거래처") {
        let custRow = ds_formulacustomerlist.getRowPosition();
        if (ds_formulacustomerlist.getRowCount() < 1 || ds_formulacustomerlist.getCellData(custRow, "clntNo") == "") {
            await $c.gus.cfAlertMsg(scwin.MSG_FS_WRN_011);
            return;
        }
    }
    let fmlaRow = ds_formulalist.getRowPosition();
    let newRow = ds_formulasellitemlist.insertRow();
    ds_formulasellitemlist.setCellData(newRow, "bilgLoofcCd", ed_bilgLoofcCd.getValue());
    ds_formulasellitemlist.setCellData(newRow, "fmlaPatternCd", ds_formulalist.getCellData(fmlaRow, "fmlaPatternCd"));
    ds_formulasellitemlist.setCellData(newRow, "fmlaClsCd", ds_formulalist.getCellData(fmlaRow, "fmlaClsCd"));
    if (rd_clntCd.getValue() == "거래처") {
        let custRow = ds_formulacustomerlist.getRowPosition();
        ds_formulasellitemlist.setCellData(newRow, "clntNo", ds_formulacustomerlist.getCellData(custRow, "clntNo"));
    } else {
        ds_formulasellitemlist.setCellData(newRow, "clntNo", "0");
    }
};

scwin.f_SellItemDelete = function() {
    if (rd_clntCd.getValue() == "공통") {
        let custRow = ds_formulacustomerlist.getRowPosition();
        if (custRow > -1) {
            ds_formulacustomerlist.removeRow(custRow);
        }
    }
    let sellRow = ds_formulasellitemlist.getRowPosition();
    if (sellRow > -1) {
        ds_formulasellitemlist.removeRow(sellRow);
    }
};

scwin.f_SellItemCancel = function() {
    if (rd_clntCd.getValue() == "공통") {
        ds_formulacustomerlist.undoAll();
    }
    ds_formulasellitemlist.undoAll();
};

scwin.f_ItemNameAddRow = async function() {
    let sellRow = ds_formulasellitemlist.getRowPosition();
    if (ds_formulasellitemlist.getRowCount() < 1 || ds_formulasellitemlist.getCellData(sellRow, "sellItemCd") == "") {
        await $c.gus.cfAlertMsg(scwin.MSG_FS_WRN_012);
        return;
    }
    let newRow = ds_sellitemnamelist.insertRow();
    ds_sellitemnamelist.setCellData(newRow, "bilgLoofcCd", ed_bilgLoofcCd.getValue());
    ds_sellitemnamelist.setCellData(newRow, "selpchItemCd", ds_formulasellitemlist.getCellData(sellRow, "sellItemCd"));
    if (rd_clntCd.getValue() == "거래처") {
        let custRow = ds_formulacustomerlist.getRowPosition();
        ds_sellitemnamelist.setCellData(newRow, "clntNo", ds_formulacustomerlist.getCellData(custRow, "clntNo"));
    } else {
        ds_sellitemnamelist.setCellData(newRow, "clntNo", "0");
    }
    ds_sellitemnamelist.setCellData(newRow, "sellGoodsPatternCd", "02");
};

scwin.f_Save = async function() {
    scwin.chk_flag = "TRUE";

    if (!ds_formulacustomerlist.isUpdated() && !ds_formulasellitemlist.isUpdated() && !ds_sellitemnamelist.isUpdated()) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["청구서유형별 매출항목 관리"]);
        return;
    }

    let chk1 = await $c.gus.cfValidate([gr_formulacustomerlist]);
    if (!chk1) {
        return;
    }

    let chk2 = await $c.gus.cfValidate([gr_formulasellitemlist]);
    if (!chk2) {
        return;
    }

    let chk3 = await $c.gus.cfValidate([gr_sellitemnamelist]);
    if (!chk3) {
        return;
    }

    let confirmResult = await $c.win.confirm(MSG_CM_CRM_001);
    if (!confirmResult) {
        return;
    }

    await $c.sbm.execute(sbm_formulsellitem_save);
};

scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    let rtnList = [];

    switch (disGubun) {
        case 1:
            udc_bilgLoofc.ilCommonPopUp(scwin.callbackBilgLoofc, pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            break;
        default:
            break;
    }
};

scwin.callbackBilgLoofc = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_bilgLoofcCd, txt_bilgLoofcNm);
};

scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }
    $c.gus.cfClearPairObj(pairObj);
    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

scwin.f_Popup = async function(disGubun) {
    let rtnList = [];
    let pCode = "";
    let pName = "";
    let sellRow;
    let custRow;
    let nameRow;

    switch (disGubun) {
        case 1:
            sellRow = ds_formulasellitemlist.getRowPosition();
            pCode = ds_formulasellitemlist.getCellData(sellRow, "sellItemCd").replace(/\s*$/, '');

            rtnList = $c.gus.cfCommonPopUp('retrieveSelpchItemInfo', pCode, pName, 'F', null, null, null, null, ',,,,,04', null, null, null, null, null, null, null);

            if (rtnList != null && rtnList[0] != "N/A") {
                ds_formulasellitemlist.setCellData(sellRow, "sellItemCd", rtnList[0]);
                ds_formulasellitemlist.setCellData(sellRow, "sellItemNm", rtnList[1]);
                ds_formulasellitemlist.setCellData(sellRow, "certiInscrpSellItemNm", rtnList[1]);
            }
            break;

        case 2:
            custRow = ds_formulacustomerlist.getRowPosition();
            pCode = ds_formulacustomerlist.getCellData(custRow, "clntNo").replace(/\s*$/, '');

            rtnList = $c.gus.cfCommonPopUp('retrieveClntList', pCode, pName, 'F', null, null, null, null, null, null, null, null, null, null, null, null);

            if (rtnList != null && rtnList[0] != "N/A") {
                if (rtnList[0] == "000000") {
                    ds_formulacustomerlist.setCellData(custRow, "clntNo", "0");
                    ds_formulacustomerlist.setCellData(custRow, "clntNm", "공통");
                } else {
                    ds_formulacustomerlist.setCellData(custRow, "clntNo", rtnList[0]);
                    ds_formulacustomerlist.setCellData(custRow, "clntNm", rtnList[1]);
                }
            }
            break;

        case 3:
            nameRow = ds_sellitemnamelist.getRowPosition();
            pCode = ds_sellitemnamelist.getCellData(nameRow, "sellCommNoDesc").replace(/\s*$/, '');

            rtnList = $c.gus.cfCommonPopUp('retrieveCommInfo', pCode, pName, 'F', null, null, null, null, null, null, null, null, null, null, null, null);

            if (rtnList != null && rtnList[0] != "N/A") {
                ds_sellitemnamelist.setCellData(nameRow, "sellCommNoDesc", rtnList[0]);
                ds_sellitemnamelist.setCellData(nameRow, "sellCommNo", rtnList[0]);
                ds_sellitemnamelist.setCellData(nameRow, "sellCommNm", rtnList[1]);
            }
            break;

        case 4:
            nameRow = ds_sellitemnamelist.getRowPosition();
            pCode = ds_sellitemnamelist.getCellData(nameRow, "sellCommNoDesc").replace(/\s*$/, '');

            let arrParam = {
                assgnLobranCd: "",
                eqKndCd: "",
                clntCd: "",
                usblDt: "",
                eqNo: pCode,
                eqNm: "",
                gubun1: "T",
                gubun2: "T"
            };

            rtnList = await $c.win.openPopup("/ui/ds/op/rscconfirm/transrscconfirm/op_101_01_12p.xml", {
                width: 600,
                height: 430,
                modal: true,
                data: arrParam
            });

            if (rtnList != null && rtnList[0] != "N/A") {
                ds_sellitemnamelist.setCellData(nameRow, "sellCommNoDesc", rtnList[1]);
                ds_sellitemnamelist.setCellData(nameRow, "sellCommNo", rtnList[12]);
                ds_sellitemnamelist.setCellData(nameRow, "sellCommNm", rtnList[2] + '(' + rtnList[3] + ')');
            }
            break;

        case 5:
            sellRow = ds_formulasellitemlist.getRowPosition();
            pCode = ds_formulasellitemlist.getCellData(sellRow, "upperSellItemCd").replace(/\s*$/, '');

            rtnList = $c.gus.cfCommonPopUp('retrieveSelpchItemInfo', pCode, pName, 'F', null, null, null, null, ',,,,,04', null, null, null, null, null, null, null);

            if (rtnList != null && rtnList[0] != "N/A") {
                ds_formulasellitemlist.setCellData(sellRow, "upperSellItemCd", rtnList[0]);
                ds_formulasellitemlist.setCellData(sellRow, "upperSellItemNm", rtnList[1]);

                let vrow = -1;
                for (let k = 0; k < ds_formulasellitemlist.getRowCount(); k++) {
                    if (ds_formulasellitemlist.getCellData(k, "sellItemCd") == ds_formulasellitemlist.getCellData(sellRow, "upperSellItemCd")) {
                        vrow = k;
                        break;
                    }
                }
                if (vrow == -1 && ds_formulasellitemlist.getCellData(sellRow, "upperSellItemCd") != "") {
                    await $c.gus.cfAlertMsg(scwin.MSG_FS_WRN_007);
                    ds_formulasellitemlist.undoRow(sellRow);
                }
            }
            break;

        case 6:
            nameRow = ds_sellitemnamelist.getRowPosition();
            pCode = ds_sellitemnamelist.getCellData(nameRow, "sellCommCd").replace(/\s*$/, '');

            rtnList = $c.gus.cfCommonPopUp('retrieveCommInfo', pCode, pName, 'F', null, null, null, null, ',,,T3', null, null, null, null, null, null, null);

            if (rtnList != null && rtnList[0] != "N/A") {
                ds_sellitemnamelist.setCellData(nameRow, "sellCommCd", rtnList[0]);
                ds_sellitemnamelist.setCellData(nameRow, "sellCommCdNm", rtnList[1]);
            }
            break;

        default:
            break;
    }
};

scwin.sbm_formulalist_retrieve_submitdone = function(e) {
};

scwin.sbm_formulalist_retrieve_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_formulasellitemlist_retrieve_submitdone = function(e) {
};

scwin.sbm_formulasellitemlist_retrieve_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_formulacustomerlist_retrieve_submitdone = function(e) {
};

scwin.sbm_formulacustomerlist_retrieve_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_formulsellitem_save_submitdone = async function(e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    scwin.chk_flag = "";

    let custRow = ds_formulacustomerlist.getRowPosition();
    if (custRow > -1 && ds_formulacustomerlist.getRowStatus(custRow) == "C") {
        scwin.f_FormulaSellItemListSetDataHeader();
        await $c.sbm.execute(sbm_formulacustomerlist_retrieve);
    }
};

scwin.sbm_formulsellitem_save_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.ds_formulalist_onloadcompleted = async function(e) {
    let rowcnt = ds_formulalist.getRowCount();
    spa_totalRows.setValue(rowcnt);

    if (rowcnt == 0) {
        ed_bilgLoofcCd.setFocus();
        $c.gus.cfDisableAllBtn();
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    } else {
        $c.gus.cfEnableObjects([btn_addRow, btn_deleteRow, btn_cancelRow, btn_addRow2, btn_deleteRow2, btn_cancelRow2]);
        $c.gus.cfEnableAllBtn();
    }
};

scwin.ds_formulacustomerlist_onloadcompleted = function(e) {
    let rowcnt = ds_formulacustomerlist.getRowCount();
    spa_totalRows2.setValue(rowcnt);
};

scwin.ds_formulasellitemlist_onloadcompleted = function(e) {
    let rowcnt = ds_formulasellitemlist.getRowCount();
    spa_totalRows3.setValue(rowcnt);
};

scwin.ds_sellitemnamelist_onloadcompleted = function(e) {
    let rowcnt = ds_sellitemnamelist.getRowCount();
    scwin.f_filterSellItemNameList();
    spa_totalRows4.setValue(ds_sellitemnamelist.getRowCount());
};

scwin.f_filterSellItemNameList = function() {
    let sellRow = ds_formulasellitemlist.getRowPosition();
    if (sellRow < 0) {
        return;
    }
    let v_val = ds_formulasellitemlist.getCellData(sellRow, "sellItemCd");
    ds_sellitemnamelist.setFilterByExpression("selpchItemCd == '" + v_val + "'");
};

scwin.ds_formulalist_onrowpositionchange = async function(e) {
    scwin.f_FormulaSellItemListSetDataHeader();
    await $c.sbm.execute(sbm_formulacustomerlist_retrieve);
};

scwin.ds_formulacustomerlist_onrowpositionchange = async function(e) {
    scwin.f_FormulaSellItemListSetDataHeader();
    await $c.sbm.execute(sbm_formulasellitemlist_retrieve);
};

scwin.ds_formulasellitemlist_onrowpositionchange = function(e) {
    scwin.f_filterSellItemNameList();
    spa_totalRows4.setValue(ds_sellitemnamelist.getRowCount());
};

scwin.ds_formulalist_onbeforerowpositionchange = async function(e) {
    let custRow = ds_formulacustomerlist.getRowPosition();
    if (custRow > -1 && ds_formulacustomerlist.getRowStatus(custRow) == "C") {
        let chk = await $c.win.confirm("저장하지 않은 거래처 데이타를 취소하시겠습니까?");
        if (chk) {
            ds_formulacustomerlist.undoAll();
            ds_formulasellitemlist.undoAll();
            ds_sellitemnamelist.undoAll();
        } else {
            return false;
        }
    }

    let sellRow = ds_formulasellitemlist.getRowPosition();
    if (sellRow > -1 && ds_formulasellitemlist.getRowStatus(sellRow) == "C") {
        let chk = await $c.win.confirm("저장하지 않은 매출항목 데이타를 취소하시겠습니까?");
        if (chk) {
            ds_formulacustomerlist.undoAll();
            ds_formulasellitemlist.undoAll();
            ds_sellitemnamelist.undoAll();
        } else {
            return false;
        }
    }

    let nameRow = ds_sellitemnamelist.getRowPosition();
    if (nameRow > -1 && ds_sellitemnamelist.getRowStatus(nameRow) == "C") {
        let chk = await $c.win.confirm("저장하지 않은 품명 데이타를 취소하시겠습니까?");
        if (chk) {
            ds_sellitemnamelist.undoAll();
        } else {
            return false;
        }
    }
};

scwin.ds_formulacustomerlist_onbeforerowpositionchange = async function(e) {
    if (scwin.chk_flag != "TRUE") {
        let sellRow = ds_formulasellitemlist.getRowPosition();
        if (sellRow > -1 && ds_formulasellitemlist.getRowStatus(sellRow) == "C") {
            let chk = await $c.win.confirm("저장하지 않은 매출항목 데이타를 취소하시겠습니까?");
            if (chk) {
                ds_formulacustomerlist.undoAll();
                ds_formulasellitemlist.undoAll();
                ds_sellitemnamelist.undoAll();
            } else {
                return false;
            }
        }

        let nameRow = ds_sellitemnamelist.getRowPosition();
        if (nameRow > -1 && ds_sellitemnamelist.getRowStatus(nameRow) == "C") {
            let chk = await $c.win.confirm("저장하지 않은 품명 데이타를 취소하시겠습니까?");
            if (chk) {
                ds_sellitemnamelist.undoAll();
            } else {
                return false;
            }
        }
    }
};

scwin.ds_formulasellitemlist_onbeforerowpositionchange = async function(e) {
    if (scwin.chk_flag != "TRUE") {
        let nameRow = ds_sellitemnamelist.getRowPosition();
        if (nameRow > -1 && ds_sellitemnamelist.getRowStatus(nameRow) == "C") {
            let chk = await $c.win.confirm("저장하지 않은 품명 데이타를 취소하시겠습니까?");
            if (chk) {
                ds_sellitemnamelist.undoAll();
            } else {
                return false;
            }
        }
    }
};

scwin.gr_formulasellitemlist_ontextimageclick = function(rowIndex, columnIndex, columnId) {
    if (columnId == "sellItemCd") {
        scwin.f_Popup(1);
    } else if (columnId == "upperSellItemCd") {
        scwin.f_Popup(5);
    }
};

scwin.gr_formulasellitemlist_oneditend = function(rowIndex, columnId, oldValue, newValue) {
    if (columnId == "sellItemCd") {
        scwin.f_Popup(1);
    } else if (columnId == "upperSellItemCd") {
        scwin.f_Popup(5);
    }
};

scwin.gr_formulacustomerlist_ontextimageclick = function(rowIndex, columnIndex, columnId) {
    scwin.f_Popup(2);
};

scwin.gr_formulacustomerlist_oneditend = function(rowIndex, columnId, oldValue, newValue) {
    if (columnId == "clntNo") {
        scwin.f_Popup(2);
    }
};

scwin.gr_sellitemnamelist_ontextimageclick = function(rowIndex, columnIndex, columnId) {
    let nameRow = ds_sellitemnamelist.getRowPosition();
    if (columnId == "sellCommNoDesc") {
        if (ds_sellitemnamelist.getCellData(nameRow, "sellGoodsPatternCd") == "02") {
            scwin.f_Popup(3);
        } else {
            scwin.f_Popup(4);
        }
    }
    if (columnId == "sellCommCd") {
        scwin.f_Popup(6);
    }
};

scwin.gr_sellitemnamelist_oneditend = function(rowIndex, columnId, oldValue, newValue) {
    if (columnId == "sellCommNoDesc") {
        if (ds_sellitemnamelist.getCellData(rowIndex, "sellGoodsPatternCd") == "02") {
            scwin.f_Popup(3);
        } else {
            scwin.f_Popup(4);
        }
    }
    if (columnId == "sellCommCd") {
        scwin.f_Popup(6);
    }
};

scwin.gr_formulasellitemlist_oncellclick = function(rowIndex, columnIndex, columnId) {
    let rowStatus = ds_formulasellitemlist.getRowStatus(rowIndex);
    if (rowStatus == "C") {
        gr_formulasellitemlist.setColumnReadOnly("sellItemCd", false);
    } else {
        gr_formulasellitemlist.setColumnReadOnly("sellItemCd", true);
    }
    gr_formulasellitemlist.setColumnReadOnly("sellItemNm", true);
    gr_formulasellitemlist.setColumnReadOnly("upperSellItemNm", true);
};

scwin.gr_formulacustomerlist_oncellclick = function(rowIndex, columnIndex, columnId) {
    let rowStatus = ds_formulacustomerlist.getRowStatus(rowIndex);
    if (rowStatus == "C") {
        gr_formulacustomerlist.setColumnReadOnly("clntNo", false);
        gr_formulacustomerlist.setColumnReadOnly("billbilgUnitclsCd", false);
    } else {
        gr_formulacustomerlist.setColumnReadOnly("clntNo", true);
        if (ds_formulacustomerlist.getCellData(rowIndex, "clntNo") == "0") {
            gr_formulacustomerlist.setColumnReadOnly("billbilgUnitclsCd", true);
        } else {
            gr_formulacustomerlist.setColumnReadOnly("billbilgUnitclsCd", false);
        }
    }
    gr_formulacustomerlist.setColumnReadOnly("clntNm", true);
};

scwin.gr_sellitemnamelist_oncellclick = function(rowIndex, columnIndex, columnId) {
    let rowStatus = ds_sellitemnamelist.getRowStatus(rowIndex);
    if (rowStatus == "C") {
        gr_sellitemnamelist.setColumnReadOnly("sellGoodsPatternCd", false);
        gr_sellitemnamelist.setColumnReadOnly("sellCommNoDesc", false);
    } else {
        gr_sellitemnamelist.setColumnReadOnly("sellGoodsPatternCd", true);
        gr_sellitemnamelist.setColumnReadOnly("sellCommNoDesc", true);
    }
    gr_sellitemnamelist.setColumnReadOnly("sellCommNm", true);
};

scwin.gr_formulasellitemlist_oncelldatachange = async function(info) {
    let row = info.row;
    let colId = info.colId;
    if (colId == "upperSellItemCd") {
        let vrow = -1;
        for (let k = 0; k < ds_formulasellitemlist.getRowCount(); k++) {
            if (ds_formulasellitemlist.getCellData(k, "sellItemCd") == ds_formulasellitemlist.getCellData(row, colId)) {
                vrow = k;
                break;
            }
        }
        if (vrow == -1 && ds_formulasellitemlist.getCellData(row, colId) != "") {
            await $c.gus.cfAlertMsg(scwin.MSG_FS_WRN_007);
            ds_formulasellitemlist.undoRow(row);
        } else if (vrow != -1) {
            if (ds_formulasellitemlist.getRowStatus(vrow) == "C") {
                await $c.gus.cfAlertMsg(scwin.MSG_FS_WRN_008);
                if (ds_formulasellitemlist.getRowStatus(row) == "C") {
                    ds_formulasellitemlist.setCellData(row, colId, "");
                } else {
                    ds_formulasellitemlist.undoRow(row);
                }
            } else {
                ds_formulasellitemlist.setCellData(row, "upperSellItemNm", ds_formulasellitemlist.getCellData(vrow, "sellItemNm"));
            }
        }
    }
};

